mapper.select:
SELECT A.PROP_CD , A.PROP_NO , A.PROP_NM , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD) AS CAT_NM , A.MID_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.MID_CAT_CD) AS MID_CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE, A.DEPOSIT, A.MONTHLY_RENT , A.AREA_EXCLUSIVE, A.ROOM_CNT, A.BATH_CNT, A.FLOOR_NO, A.FLOOR_TOTAL , A.ADDRESS, A.ADDRESS_DTL , A.LAT, A.LNG , A.SOLD_YN , DATE_FORMAT(A.CRE_DTM, '%Y-%m-%d') AS CRE_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y' AND A.SOLD_YN = 'N' AND A.LAT IS NOT NULL AND A.LNG IS NOT NULL
AND A.LAT BETWEEN #{swLat} AND #{neLat} AND A.LNG BETWEEN #{swLng} AND #{neLng}
AND A.CAT_CD = #{catCd}
AND A.DEAL_TYPE = #{dealType}
ORDER BY A.CRE_DTM DESC LIMIT 100

SELECT A.PROP_CD , A.PROP_NO , A.PROP_NM , A.CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.CAT_CD) AS CAT_NM , A.MID_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.MID_CAT_CD) AS MID_CAT_NM , A.SUB_CAT_CD , (SELECT C.CAT_NM FROM TB_PROP_CATEGORY C WHERE C.CAT_CD = A.SUB_CAT_CD) AS SUB_CAT_NM , A.DEAL_TYPE , CASE A.DEAL_TYPE WHEN 'SELL' THEN '매매' WHEN 'JEONSE' THEN '전세' WHEN 'WOLSE' THEN '월세' WHEN 'SHORT' THEN '단기임대' ELSE '' END AS DEAL_TYPE_NM , A.SELL_PRICE, A.DEPOSIT, A.MONTHLY_RENT , A.AREA_EXCLUSIVE, A.ROOM_CNT, A.BATH_CNT, A.FLOOR_NO, A.FLOOR_TOTAL , A.ADDRESS, A.SOLD_YN , A.ATCH_FILE_KEY , A.THUMB_IMG_PATH AS THUMB_PATH , DATE_FORMAT(A.CRE_DTM, '%Y-%m-%d') AS CRE_DTM FROM TB_PROPERTY A WHERE A.DEL_YN = 'N' AND A.USE_YN = 'Y'
AND A.CAT_CD = UPPER(#{catCd})
AND A.MID_CAT_CD = #{midCatCd}
AND A.SUB_CAT_CD = #{subCatCd}
AND A.DEAL_TYPE = #{dealType}
AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))
AND A.AREA_EXCLUSIVE >= #{areaMin}
AND A.AREA_EXCLUSIVE <= #{areaMax}
AND ( (A.DEAL_TYPE = 'SELL' AND A.SELL_PRICE >= #{priceMin}) OR (A.DEAL_TYPE IN ('JEONSE', 'WOLSE', 'RENT', 'SHORT') AND A.DEPOSIT >= #{priceMin}) )
AND ( (A.DEAL_TYPE = 'SELL' AND A.SELL_PRICE <= #{priceMax}) OR (A.DEAL_TYPE IN ('JEONSE', 'WOLSE', 'RENT', 'SHORT') AND A.DEPOSIT <= #{priceMax}) )
AND A.MONTHLY_RENT >= #{rentMin}
AND A.MONTHLY_RENT <= #{rentMax}
AND A.FLOOR_NO = 1
AND A.FLOOR_NO >= 2
AND (A.FLOOR_NO < 0 OR A.FLOOR_NO LIKE 'B%' OR A.FLOOR_NO LIKE '지하%')
ORDER BY CASE A.SOLD_YN WHEN 'N' THEN 0 ELSE 1 END ASC, A.CRE_DTM DESC LIMIT ${offset}, ${pageSize}

SELECT COUNT(*)
  FROM TB_PROPERTY A
 WHERE A.DEL_YN = 'N'
   AND A.USE_YN = 'Y'

   AND A.CAT_CD = UPPER(#{catCd})


   AND A.MID_CAT_CD = #{midCatCd}


   AND A.SUB_CAT_CD = #{subCatCd}


   AND A.DEAL_TYPE = #{dealType}


   AND (A.PROP_NM LIKE CONCAT('%', #{keyword}, '%') OR A.ADDRESS LIKE CONCAT('%', #{keyword}, '%'))


   AND A.AREA_EXCLUSIVE >= #{areaMin}


   AND A.AREA_EXCLUSIVE <= #{areaMax}



   AND (
       (A.DEAL_TYPE = 'SELL' AND A.SELL_PRICE >= #{priceMin})
       OR (A.DEAL_TYPE IN ('JEONSE', 'WOLSE', 'RENT', 'SHORT') AND A.DEPOSIT >= #{priceMin})
   )


   AND (
       (A.DEAL_TYPE = 'SELL' AND A.SELL_PRICE <= #{priceMax})
       OR (A.DEAL_TYPE IN ('JEONSE', 'WOLSE', 'RENT', 'SHORT') AND A.DEPOSIT <= #{priceMax})
   )



   AND A.MONTHLY_RENT >= #{rentMin}


   AND A.MONTHLY_RENT <= #{rentMax}



   AND A.FLOOR_NO = 1


   AND A.FLOOR_NO >= 2


   AND (A.FLOOR_NO < 0 OR A.FLOOR_NO LIKE 'B%' OR A.FLOOR_NO LIKE '지하%')

mapper.update:
UPDATE TB_PROPERTY
   SET VIEW_CNT = VIEW_CNT + 1
 WHERE PROP_CD = #{id}
